package models

import "time"

// MonitorResult holds the result of a single monitor check
type MonitorResult struct {
	Target  string        `json:"target"`
	Status  string        `json:"status"`
	Code    int           `json:"code"`
	Latency time.Duration `json:"latency"`
	Error   string        `json:"error"`
	Success bool          `json:"success"`
}

// Target represents a single endpoint to monitor
type Target struct {
	Protocol    string `json:"protocol"`
	Address     string `json:"address"`
	IntervalSec int    `json:"interval_sec"` // interval in seconds between checks
}

// Config represents the JSON configuration file structure
type Config struct {
	HTTP []string `json:"http"`
	TCP  []string `json:"tcp"`
}

package models

import "time"

// MonitorResult holds the result of a single monitor check
type MonitorResult struct {
	Target  string        `json:"target"`
	Protocol string       `json:"protocol"`
	Status  string        `json:"status"`
	Code    int           `json:"code"`
	Latency time.Duration `json:"latency"`
	Error   string        `json:"error"`
	Success bool          `json:"success"`
}

// Target represents a single endpoint to monitor
type Target struct {
	// Type indicates the type of check to perform: "http", "http-head", "tcp", etc.
	Type        string `json:"type"`
	// Protocol is kept for backward compatibility; it's typically the same as Type.
	Protocol    string `json:"protocol"`
	Address     string `json:"address"`
	IntervalSec int    `json:"interval_sec"` // interval in seconds between checks
}

// Config represents the JSON configuration file structure
type Config struct {
	HTTP []string `json:"http"`
	TCP  []string `json:"tcp"`
}
